package org.jetbrains.letsPlot.core.plot.base.render.text

internal data class VectorGlyph(
    val advanceEm: Double,   // horizontal advance, em units (1.0 == 1 em)
    val pathData: String?    // SVG path-data, em units * 1000; null for blank glyphs (e.g. space)
)

internal object LatexVectorFont {
    // Per-glyph design coordinates are in this UPM. The renderer scales by fontSize/UPM.
    const val UPM: Int = 1000

    // Word-wrapping can inject '\n'/'\t'/'\r' inside a formula; register them as zero-advance blanks
    // so they're ignored and the formula doesn't fall back to the legacy tspan renderer.
    // TODO: remove once wrap() is LaTeX-aware and never injects whitespace other than ' ' into a formula.
    private val WHITESPACE_GLYPH = VectorGlyph(advanceEm = 0.0, pathData = null)
    private val WHITESPACE_GLYPHS = mapOf('\n' to WHITESPACE_GLYPH, '\t' to WHITESPACE_GLYPH, '\r' to WHITESPACE_GLYPH)

    private val GLYPHS_REGULAR: Map<Char, VectorGlyph> = buildLatexGlyphTableRegular() + WHITESPACE_GLYPHS
    private val GLYPHS_BOLD: Map<Char, VectorGlyph> = buildLatexGlyphTableBold() + WHITESPACE_GLYPHS
    private val GLYPHS_OBLIQUE: Map<Char, VectorGlyph> = buildLatexGlyphTableOblique() + WHITESPACE_GLYPHS
    private val GLYPHS_BOLD_OBLIQUE: Map<Char, VectorGlyph> = buildLatexGlyphTableBoldOblique() + WHITESPACE_GLYPHS

    private fun table(bold: Boolean, italic: Boolean): Map<Char, VectorGlyph> = when {
        bold && italic -> GLYPHS_BOLD_OBLIQUE
        bold -> GLYPHS_BOLD
        italic -> GLYPHS_OBLIQUE
        else -> GLYPHS_REGULAR
    }

    fun isSupported(char: Char, bold: Boolean = false, italic: Boolean = false): Boolean = table(bold, italic).containsKey(char)
    fun isSupported(text: String, bold: Boolean = false, italic: Boolean = false): Boolean = text.all { isSupported(it, bold, italic) }
    fun glyphOrNull(char: Char, bold: Boolean = false, italic: Boolean = false): VectorGlyph? = table(bold, italic)[char]
    fun advanceEm(char: Char, bold: Boolean = false, italic: Boolean = false): Double =
        table(bold, italic)[char]?.advanceEm ?: error("vector advance requested for unsupported char: U+${char.code.toString(16).padStart(4, '0').uppercase()}")
}

